import React, { useState } from "react";
import {
  Card,
  CardActionArea,
  CardHeader,
  IconButton,
  CircularProgress,
  makeStyles,
} from "@material-ui/core";
import Edit from "@material-ui/icons/Edit";

const useStyles = makeStyles({
  card: {
    position: "relative",
  },
  cardActionArea: {
    userSelect: "none",
    touchAction: "manipulation",
    "-webkitTouchCallout": "none",
  },
  cardDisableHover: {
    opacity: [["0"], "!important"] as any,
  },
  headerAction: {
    margin: "0px 4px",
  },
  headerTitle: {
    padding: "0px 12px",
    whiteSpace: "nowrap",
    textOverflow: "ellipsis",
    overflow: "hidden",
  },
  headerTitleContainer: {
    minWidth: 0,
  },
  loadingDiv: {
    position: "absolute",
    top: 0,
    left: 0,
    height: "100%",
    width: "100%",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
});

interface Props {
  onDivRef(ref: HTMLDivElement): void;
  onMouseDown: React.MouseEventHandler;
  onMouseUp: React.MouseEventHandler;
  onTouchStart: React.TouchEventHandler;
  onTouchEnd: React.TouchEventHandler;
  onTouchMove: React.TouchEventHandler;
  loading: boolean;
  title?: string;
  onEditClick(): void;
}

export default (props: Props) => {
  const {
    loading,
    title,
    onDivRef,
    onMouseDown,
    onMouseUp,
    onTouchStart,
    onTouchEnd,
    onTouchMove,
    onEditClick,
  } = props;
  const classes = useStyles();
  const [cornerIconEntered, setCornerIconEntered] = useState(false);

  return (
    <Card className={classes.card}>
      <CardActionArea
        disableRipple
        disabled={loading}
        onMouseDown={onMouseDown}
        onMouseUp={onMouseUp}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
        classes={{
          focusHighlight: cornerIconEntered
            ? classes.cardDisableHover
            : undefined,
        }}
        className={classes.cardActionArea}
      >
        <CardHeader
          title={title}
          classes={{
            action: classes.headerAction,
            title: classes.headerTitle,
            content: classes.headerTitleContainer,
          }}
          action={
            <IconButton
              component="div"
              onMouseOver={() => setCornerIconEntered(true)}
              onMouseOut={() => setCornerIconEntered(false)}
              onTouchStart={(evt: React.TouchEvent<HTMLDivElement>) =>
                evt.stopPropagation()
              }
              onTouchEnd={(evt: React.TouchEvent<HTMLDivElement>) =>
                evt.stopPropagation()
              }
              onMouseDown={(evt: React.MouseEvent<HTMLDivElement>) =>
                evt.stopPropagation()
              }
              onMouseUp={(evt: React.MouseEvent<HTMLDivElement>) =>
                evt.stopPropagation()
              }
              onClick={onEditClick}
            >
              <Edit />
            </IconButton>
          }
          style={{ padding: "4px 0px" }}
        />
        <div ref={onDivRef} style={{ height: 128 }} />
      </CardActionArea>
      {loading && (
        <div className={classes.loadingDiv}>
          <CircularProgress />
        </div>
      )}
    </Card>
  );
};
